'use strict';

const defaults = {
  smoke_mode: true,
  pkm_test_mode: true,
  calendar_test_mode: true,
  smoke_telegram_dry_run: true,
  telegram_test_chat_id: '1509032341',
  test_calendar_id: '831dca29672745da07709e8636e37b6241df174fca270982c66a046b915b2dc1@group.calendar.google.com',
  prod_calendar_id: 'pkm.gasovic@gmail.com',
  allow_test_calendar_purge: false,
  public_ingress_path: 'pkm/smoke/ingress',
};
const now = new Date();
const pad = (v) => String(v).padStart(2, '0');
const runId = [
  'smoke',
  now.getUTCFullYear(),
  pad(now.getUTCMonth() + 1),
  pad(now.getUTCDate()),
  pad(now.getUTCHours()) + pad(now.getUTCMinutes()) + pad(now.getUTCSeconds()),
].join('_');

return [{
  json: {
    ...defaults,
    test_run_id: runId,
    started_at: now.toISOString(),
    results: [],
    artifacts: {},
    smoke_mode: true,
    pkm_test_mode: true,
    calendar_test_mode: true,
  },
}];

'use strict';

const base = { ...$json };
const results = Array.isArray(base.results) ? [...base.results] : [];
const headers = { 'X-PKM-Run-Id': String(base.test_run_id || '') };
let prior = null;
let ok = false;
let error = null;

try {
  const stateRows = await helpers.httpRequest({
    method: 'GET',
    url: 'http://pkm-server:8080/db/test-mode',
    headers,
    json: true,
  });
  const first = Array.isArray(stateRows) ? stateRows[0] : null;
  prior = !!(first && first.is_test_mode === true);

  if (!prior) {
    await helpers.httpRequest({
      method: 'POST',
      url: 'http://pkm-server:8080/db/test-mode/toggle',
      headers,
      json: true,
      body: {},
    });
  }
  ok = true;
} catch (e) {
  error = { message: String(e && e.message ? e.message : e) };
}

results.push({
  test_case: 'T00-test-mode-setup',
  ok,
  run_id: base.test_run_id || null,
  artifacts: { prior_test_mode: prior },
  assertions: [
    { name: 'test_mode_state_read', ok: prior !== null },
    { name: 'test_mode_enabled_for_run', ok },
  ],
  error,
});

return [{ json: { ...base, prior_test_mode: prior, results } }];

'use strict';

const base = { ...$json };
const results = Array.isArray(base.results) ? [...base.results] : [];
const headers = { 'X-PKM-Run-Id': String(base.test_run_id || '') };

let health = null;
let ready = null;
let probe = null;
let error = null;

try {
  health = await helpers.httpRequest({ method: 'GET', url: 'http://pkm-server:8080/health', headers, json: true });
  ready = await helpers.httpRequest({ method: 'GET', url: 'http://pkm-server:8080/ready', headers, json: true });
  probe = await helpers.httpRequest({
    method: 'POST',
    url: 'http://pkm-server:8080/db/read/last',
    headers,
    json: true,
    body: { q: 'smoke', days: 7, limit: 1 },
  });
} catch (e) {
  error = { message: String(e && e.message ? e.message : e) };
}

const assertions = [
  { name: 'health_status_ok', ok: !!health && health.status === 'ok' },
  { name: 'ready_status_ok', ok: !!ready && ready.status === 'ready' },
  { name: 'db_probe_completed', ok: error == null && (Array.isArray(probe) || probe != null) },
];
const ok = assertions.every((a) => a.ok === true);

results.push({
  test_case: 'T01-infra',
  ok,
  run_id: base.test_run_id || null,
  artifacts: {
    health: health || null,
    ready: ready || null,
  },
  assertions,
  error,
});

return [{ json: { ...base, results } }];

'use strict';

const base = { ...$json };
const results = Array.isArray(base.results) ? [...base.results] : [];
let response = null;
let error = null;

const ingressPath = String(base.public_ingress_path || 'pkm/smoke/ingress').replace(/^\/+/, '');
const url = 'https://n8n-hook.gasovic.com/' + ingressPath;

try {
  response = await helpers.httpRequest({
    method: 'POST',
    url,
    json: true,
    timeout: 30000,
    body: {
      smoke: true,
      test_run_id: base.test_run_id || null,
      ts: new Date().toISOString(),
    },
  });
} catch (e) {
  error = { message: String(e && e.message ? e.message : e) };
}

const assertions = [
  { name: 'public_webhook_called', ok: !error },
  { name: 'public_webhook_ok', ok: !!response && response.ok === true },
];
const ok = assertions.every((a) => a.ok === true);

results.push({
  test_case: 'T02-public-ingress',
  ok,
  run_id: base.test_run_id || null,
  artifacts: {
    ingress_url: url,
    ingress_response: response || null,
  },
  assertions,
  error,
});

return [{ json: { ...base, results } }];

